UPDATE
	UNTACT_BOOK_RESERVATION
SET
	locker_type = #{locker_type}
WHERE
	homepage_id = #{homepage_id}
AND member_id = #{member_id}
AND reservation_step = #{reservation_step}
AND TO_CHAR(request_date, 'yyyy-MM-dd') = TO_CHAR(SYSDATE, 'yyyy-MM-dd')

UPDATE
	UNTACT_BOOK_RESERVATION
SET
	locker_password = #{locker_password}
WHERE
	homepage_id = #{homepage_id}
AND request_number = #{request_number}
AND cancel_yn = 'N'
AND locker_password = 0


	AND TO_CHAR(request_date,'yyyy-MM-dd') BETWEEN #{start_date} AND #{end_date}

UPDATE
	UNTACT_BOOK_RESERVATION
SET
	reservation_step = #{reservation_step},
	loan_date = SYSDATE
WHERE
	homepage_id = #{homepage_id}
AND member_id = #{member_id}
AND request_number = #{request_number}


	AND TO_CHAR(request_date,'yyyy-MM-dd') BETWEEN #{start_date} AND #{end_date}

